#include<bits/stdc++.h>
using namespace std;
const long long N=100010;
long long dfn[N],rnk[N],val[N],top[N],dfncnt,siz[N],son[N],fa[N],d[N];
vector<pair<long long,long long>> mp[N];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(auto i:mp[x])
    {
        int v=i.first;
        if(v!=f)
        {
            d[v]=d[x]+1;
            fa[v]=x;
            val[v]=i.second;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto v:mp[x])
        {
            int i=v.first;
            if(i!=fa[x]&&i!=son[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r,max1,lazy;
        node():lazy(-1){}
    }a[N*4];
    void pushup(long long x)
    {
        a[x].max1=max(a[x<<1].max1,a[x<<1|1].max1);
    }
    void pushdown(long long x)
    {
        if(a[x].lazy==-1)
        {
            return;
        }
        a[x<<1].lazy=a[x].lazy;
        a[x<<1|1].lazy=a[x].lazy;
        a[x<<1].max1=a[x].lazy;
        a[x<<1|1].max1=a[x].lazy;
        a[x].lazy=-1;
    }
    void init(long long x,long long l,long long r)
    {
        long long mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].max1=val[rnk[l]];
            return;
        }
        init(x<<1,l,mid);
        init(x<<1|1,mid+1,r);
        pushup(x);
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].lazy=z;
            a[x].max1=z;
            return;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        pushdown(x);
        if(l<=mid)
        {
            update(x<<1,l,r,z);
        }
        if(r>mid)
        {
            update(x<<1|1,l,r,z);
        }
        pushup(x);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        long long mid=(a[x].l+a[x].r)/2,ans=0;
        pushdown(x);
        if(l<=mid)
        {
            ans=getmax(x<<1,l,r);
        }
        if(r>mid)
        {
            ans=max(ans,getmax(x<<1|1,l,r));
        }
        return ans;
    }
}t;
long long query(long long x,long long y)
{
    long long tx=top[x],ty=top[y],ans=0;
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            ans=max(ans,t.getmax(1,dfn[tx],dfn[x]));
            x=fa[tx];
        }
        else
        {
            ans=max(ans,t.getmax(1,dfn[ty],dfn[y]));
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=max(ans,t.getmax(1,dfn[x]+1,dfn[y]));
    return ans;
}
long long u[N],v[N];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long x,y,z;
        scanf("%lld%lld%lld",&x,&y,&z);
        u[i]=x,v[i]=y;
        mp[x].push_back(make_pair(y,z));
        mp[y].push_back(make_pair(x,z));
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,1,n);
    while(1)
    {
        string s;
        cin>>s;
        if(s=="DONE")
        {
            break;
        }
        int x,y;
        scanf("%d%d",&x,&y);
        if(s=="CHANGE")
        {
            int a=u[x],b=v[x];
            if(d[a]<d[b])
            {
                swap(a,b);
            }
            t.update(1,dfn[a],dfn[a],y);
        }
        else
        {
            printf("%lld\n",query(x,y));
        }
    }
    return 0;
}
